import ast, os

root = "litellm"
defs = {}
for dirpath, _, files in os.walk(root):
    for f in files:
        if not f.endswith(".py"): continue
        p = os.path.join(dirpath, f)
        try: tree = ast.parse(open(p, encoding="utf-8").read(), p)
        except Exception: continue
        for node in ast.walk(tree):
            if isinstance(node, ast.ClassDef):
                bases=[]
                for b in node.bases:
                    if isinstance(b, ast.Name): bases.append(b.id)
                    elif isinstance(b, ast.Attribute): bases.append(b.attr)
                    elif isinstance(b, ast.Subscript):
                        v=b.value
                        if isinstance(v, ast.Name): bases.append(v.id)
                        elif isinstance(v, ast.Attribute): bases.append(v.attr)
                defs.setdefault(node.name, []).append((bases, p, node.lineno))

children={}
for name, entries in defs.items():
    for bases,p,ln in entries:
        for b in bases: children.setdefault(b,set()).add(name)

def closure(start, blocked=frozenset()):
    reached=set(); frontier=[start]
    while frontier:
        cur=frontier.pop()
        for ch in children.get(cur,()):
            if ch in blocked: continue
            if ch not in reached:
                reached.add(ch); frontier.append(ch)
    return reached

# other-modality roots that redefine the contract for a non-chat modality
modality_roots = ["BaseEmbeddingConfig","BaseAudioTranscriptionConfig","BaseFilesConfig",
                  "BaseImageVariationConfig","BaseTextCompletionConfig","BaseImageGenerationConfig",
                  "BaseRerankConfig","BaseResponsesAPIConfig","BaseAnthropicMessagesConfig"]
modality_members = set()
for r in modality_roots:
    modality_members |= closure(r)
    modality_members.add(r)

all_reached = closure("BaseConfig")
chat = all_reached - modality_members
# OpenAITextCompletionConfig extends both — it's chat-capable; keep note separately
print("all reached:", len(all_reached), "| modality:", len(modality_members), "| chat-scope:", len(chat))
print("\n=== CHAT-SCOPE provider configs (name  file:line  bases) ===")
rows=[]
for name in chat:
    for bases,p,ln in defs.get(name,[]):
        if name in closure("BaseConfig") and any(b in ("BaseEmbeddingConfig","BaseAudioTranscriptionConfig","BaseFilesConfig","BaseImageVariationConfig","BaseTextCompletionConfig") for b in bases):
            continue
        rows.append((p,ln,name,bases))
for p,ln,name,bases in sorted(rows):
    print(f"{p}:{ln}\t{name}\tbases={bases}")
